import{_ as a,o as e,c as o,ae as i}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Apple Ads SKAN Support","description":"","frontmatter":{"title":"Apple Ads SKAN Support","slug":"apple-ads-skan-support"},"headers":[],"relativePath":"account-hub/apple-ads-skan-support.md","filePath":"account-hub/apple-ads-skan-support.md"}'),d={name:"account-hub/apple-ads-skan-support.md"};function l(s,t,r,p,n,c){return e(),o("div",null,[...t[0]||(t[0]=[i('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Branch is happy to share that Apple Ads (previously Apple Ads) now supports SKAdNetwork (SKAN) attribution tracking! This update helps you better understand how users discover and download your iOS app through Apple&#39;s advertising platform.</p><p>Please note, this is <strong>available for SKAN versions 1.0, 2.0, and 3.0 only</strong>.</p><h2 id="key-updates" tabindex="-1">Key updates <a class="header-anchor" href="#key-updates" aria-label="Permalink to &quot;Key updates&quot;">​</a></h2><ul><li><strong>Live now</strong>: Full attribution tracking support and enhanced dashboard reporting.</li><li><strong>Coming April 28</strong>: Detailed campaign mapping (see the <a href="./apple-ads-skan-support.html#technical-data-mappings">“Technical data mappings” section</a> below).</li></ul><h2 id="what-this-means-for-you" tabindex="-1">What this means for you <a class="header-anchor" href="#what-this-means-for-you" aria-label="Permalink to &quot;What this means for you&quot;">​</a></h2><p>If you enable SKAN attribution tracking with Apple Ads, you&#39;ll get better insights into how users find your app through:</p><ul><li>App Store search results</li><li>App Store Today tab</li><li>App Store Search tab</li><li>App Store product pages</li></ul><h2 id="what-to-do-next" tabindex="-1">What to do next <a class="header-anchor" href="#what-to-do-next" aria-label="Permalink to &quot;What to do next&quot;">​</a></h2><p>If you want to access this new attribution data, you&#39;ll need to:</p><ol><li><p>Enable <a href="./skadnetwork-direct-postback.html">SKAN direct postbacks</a>.</p></li><li><p>Have your technical team implement a simple app update.</p></li></ol><div class="warning custom-block"><p class="custom-block-title">Warning</p><p>If you do not take these steps, your app will remain unaffected, but you will not have access to SKAN attribution data for Apple Ads.</p></div><h2 id="technical-data-mappings" tabindex="-1">Technical data mappings <a class="header-anchor" href="#technical-data-mappings" aria-label="Permalink to &quot;Technical data mappings&quot;">​</a></h2><p>The table in this section details how Branch maps Apple Ads fields to Branch fields.</p><p>These mappings will be <strong>available April 28</strong>.</p><p>Additional notes about the columns:</p><ul><li><code>body_campaign_id</code>: Apple will only send Branch 4 possible values for this field.</li><li><code>last_attributed_touch_data_tilde_campaign</code>: Branch takes <code>body_campaign_id</code> and maps it to this field.</li><li><strong>Touch type</strong>: The value for this field will alway be “Taps” (clicks).</li><li><code>body_fidelity_type</code>: Branch reflects the touch type in this field, using the value 1 to indicate clicks.</li></ul><table tabindex="0"><thead><tr><th><code>body_campaign_id</code></th><th><code>last_attributed_touch_data_tilde_campaign</code></th><th>Touch type</th><th><code>body_fidelity_type</code></th></tr></thead><tbody><tr><td>10</td><td>APPSTORE_SEARCH_RESULTS</td><td>Taps</td><td>1</td></tr><tr><td>20</td><td>APPSTORE_TODAY_TAB</td><td>Taps</td><td>1</td></tr><tr><td>30</td><td>APPSTORE_SEARCH_TAB</td><td>Taps</td><td>1</td></tr><tr><td>40</td><td>APPSTORE_PRODUCT_PAGES_BROWSE</td><td>Taps</td><td>1</td></tr></tbody></table><h2 id="additional-resources" tabindex="-1">Additional resources <a class="header-anchor" href="#additional-resources" aria-label="Permalink to &quot;Additional resources&quot;">​</a></h2><p>For more detailed help:</p><ul><li>Check out our <a href="./skadnetwork-index.html">additional SKAdNetwork documentation</a>.</li><li>Contact your account manager for support.</li></ul>',21)])])}const b=a(d,[["render",l]]);export{u as __pageData,b as default};
